import React, { useEffect, useMemo, useState } from "react";
import StatusBadge from "./StatusBadge";
import { normalizeStatus } from "./statusConfig";

const RECORDS_PER_PAGE = 10;

function formatDayLabel(timestamp) {
  return new Intl.DateTimeFormat("en-IN", {
    weekday: "long",
    day: "2-digit",
    month: "short",
    year: "numeric",
  }).format(new Date(timestamp));
}

function formatTimeLabel(timestamp) {
  return new Intl.DateTimeFormat("en-IN", {
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
  }).format(new Date(timestamp));
}

function getDayKey(timestamp) {
  const date = new Date(timestamp);
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function sortByTimestamp(records, daySort) {
  const sorted = [...records];

  sorted.sort((a, b) => {
    const aTime = new Date(a.timestamp).getTime();
    const bTime = new Date(b.timestamp).getTime();
    return daySort === "oldest" ? aTime - bTime : bTime - aTime;
  });

  return sorted;
}

function groupHistoryByDay(records) {
  const groups = [];
  let currentGroup = null;

  records.forEach((record) => {
    const dayKey = getDayKey(record.timestamp);

    if (!currentGroup || currentGroup.dayKey !== dayKey) {
      currentGroup = {
        dayKey,
        dayLabel: formatDayLabel(record.timestamp),
        records: [],
      };
      groups.push(currentGroup);
    }

    currentGroup.records.push(record);
  });

  return groups;
}

function HistoryView({ history, histLoading }) {
  const [currentPage, setCurrentPage] = useState(1);
  const [statusFilter, setStatusFilter] = useState("All");
  const [daySort, setDaySort] = useState("newest");

  const statusOptions = [
    "All",
    ...new Set(history.map((row) => normalizeStatus(row.predicted_status)).filter(Boolean)),
  ];

  const filteredHistory =
    statusFilter === "All"
      ? history
      : history.filter((row) => normalizeStatus(row.predicted_status) === statusFilter);

  const sortedHistory = useMemo(
    () => sortByTimestamp(filteredHistory, daySort),
    [filteredHistory, daySort],
  );

  useEffect(() => {
    setCurrentPage(1);
  }, [history, histLoading, statusFilter, daySort]);

  const totalPages = Math.ceil(sortedHistory.length / RECORDS_PER_PAGE);
  const startIndex = (currentPage - 1) * RECORDS_PER_PAGE;
  const visibleHistory = sortedHistory.slice(startIndex, startIndex + RECORDS_PER_PAGE);
  const groupedHistory = useMemo(() => groupHistoryByDay(visibleHistory), [visibleHistory]);
  const pageStart = sortedHistory.length === 0 ? 0 : startIndex + 1;
  const pageEnd = Math.min(startIndex + RECORDS_PER_PAGE, sortedHistory.length);

  return (
    <section className="panel mainPanel">
      <div className="historyViewHeader">
        <div>
          <h2>Prediction History</h2>
          <p>Records are grouped by day using the database timestamp.</p>
        </div>
        <div className="historyControls">
          <label className="historyFilter">
            <span>Status</span>
            <select
              className="historyFilterSelect"
              value={statusFilter}
              onChange={(event) => setStatusFilter(event.target.value)}
            >
              {statusOptions.map((status) => (
                <option key={status} value={status}>
                  {status}
                </option>
              ))}
            </select>
          </label>
          <div className="historySortBlock">
            <span className="historySortLabel">Day Sort</span>
            <div className="historySortOptions">
              <button
                type="button"
                className={`historySortChip ${daySort === "newest" ? "active" : ""}`}
                onClick={() => setDaySort("newest")}
                aria-pressed={daySort === "newest"}
              >
                Latest Day
              </button>
              <button
                type="button"
                className={`historySortChip ${daySort === "oldest" ? "active" : ""}`}
                onClick={() => setDaySort("oldest")}
                aria-pressed={daySort === "oldest"}
              >
                Oldest Day
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="historyCard">
        {histLoading ? (
          <div className="tableSkeleton" aria-hidden="true">
            <div className="skeletonLine skeletonLineWide" />
            <div className="skeletonLine" />
            <div className="skeletonLine" />
            <div className="skeletonLine" />
          </div>
        ) : history.length === 0 ? (
          <div className="emptyState">
            <strong>No history yet</strong>
            <p>Prediction records will appear here after you run the first safety check.</p>
          </div>
        ) : filteredHistory.length === 0 ? (
          <div className="emptyState">
            <strong>No matching records</strong>
            <p>Try another status filter to see more prediction history.</p>
          </div>
        ) : (
          <>
            {groupedHistory.map((group) => (
              <div key={group.dayKey} className="historyDayGroup">
                <div className="historyDayHeader">
                  <h3>{group.dayLabel}</h3>
                  <span>{group.records.length} record{group.records.length > 1 ? "s" : ""}</span>
                </div>

                <table className="historyTable">
                  <thead>
                    <tr>
                      <th>#</th>
                      <th>Time</th>
                      <th>Distance</th>
                      <th>TTC</th>
                      <th>Rel. Velocity</th>
                      <th>Status</th>
                    </tr>
                  </thead>
                  <tbody>
                    {group.records.map((row) => (
                      <tr key={row.id}>
                        <td>{row.id}</td>
                        <td>{formatTimeLabel(row.timestamp)}</td>
                        <td>{row.distance.toFixed(1)} m</td>
                        <td>{row.ttc === null ? "N/A" : `${row.ttc.toFixed(2)} s`}</td>
                        <td>{row.relative_velocity.toFixed(1)} m/s</td>
                        <td>
                          <StatusBadge status={row.predicted_status} />
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            ))}

            <div className="historyPagination">
              <span className="historyPageInfo">
                Showing {pageStart}-{pageEnd} of {sortedHistory.length} records
              </span>

              {totalPages > 1 ? (
                <div className="historyPaginationActions">
                  <span className="historyPageInfo">
                    Page {currentPage} of {totalPages}
                  </span>
                  <button
                    type="button"
                    className="historyPageButton"
                    onClick={() => setCurrentPage((page) => page - 1)}
                    disabled={currentPage === 1}
                  >
                    Previous
                  </button>
                  <button
                    type="button"
                    className="historyPageButton"
                    onClick={() => setCurrentPage((page) => page + 1)}
                    disabled={currentPage === totalPages}
                  >
                    Next Page
                  </button>
                </div>
              ) : null}
            </div>
          </>
        )}
      </div>
    </section>
  );
}

export default HistoryView;
